// src/auth/core/RegisterUseCase.ts
class RegisterUseCase {
  userRepository;
  constructor(userRepository) {
    this.userRepository = userRepository;
  }
  async execute(dto) {
    const existingUser = await this.userRepository.findByEmail(dto.email);
    if (existingUser) {
      throw new Error("Email is already registered");
    }
    if (dto.role === "admin") {
      const adminExists = await this.userRepository.existsAdmin();
      if (adminExists) {
        throw new Error("An administrator already exists. SmartPyME is a single-tenant system.");
      }
    }
    const passwordHash = await bcryptjs_default.hash(dto.password, 10);
    const newUser = User.create({
      id: crypto.randomUUID(),
      email: dto.email,
      passwordHash,
      name: dto.name,
      phone: dto.phone,
      role: dto.role,
      isActive: true
    });
    await this.userRepository.save(newUser);
    return newUser;
  }
}

