// src/auth/adapters/SqliteUserRepo.ts
class SqliteUserRepo {
  toDomain(row) {
    return new User(row.id, row.email, row.passwordHash, row.name, row.phone, row.role, row.defaultShippingAddress, row.isActive === 1, row.createdAt, row.updatedAt);
  }
  async findByEmail(email3) {
    const [row] = await db.select().from(users).where(eq(users.email, email3)).limit(1);
    if (!row)
      return null;
    return this.toDomain(row);
  }
  async findById(id) {
    const [row] = await db.select().from(users).where(eq(users.id, id)).limit(1);
    if (!row)
      return null;
    return this.toDomain(row);
  }
  async save(user) {
    await db.insert(users).values({
      id: user.id,
      email: user.email,
      passwordHash: user.passwordHash,
      name: user.name,
      phone: user.phone,
      role: user.role,
      defaultShippingAddress: user.defaultShippingAddress,
      isActive: user.isActive ? 1 : 0,
      createdAt: user.createdAt,
      updatedAt: user.updatedAt
    }).onConflictDoUpdate({
      target: users.id,
      set: {
        email: user.email,
        passwordHash: user.passwordHash,
        name: user.name,
        phone: user.phone,
        role: user.role,
        defaultShippingAddress: user.defaultShippingAddress,
        isActive: user.isActive ? 1 : 0,
        updatedAt: new Date().toISOString()
      }
    });
  }
  async existsAdmin() {
    const [row] = await db.select({ count: sql`count(*)` }).from(users).where(eq(users.role, "admin")).limit(1);
    return Number(row?.count || 0) > 0;
  }
}

// src/shared/infrastructure/middleware/auth.ts
function authMiddleware(roles) {
  return async (c, next) => {
    const authHeader = c.req.header("Authorization");
    if (!authHeader || !authHeader.startsWith("Bearer ")) {
      return c.json({
        success: false,
        error: "Unauthorized: Missing or invalid Authorization header"
      }, 401);
    }
    const token = authHeader.substring(7);
    try {
      const secret = new TextEncoder().encode(process.env.JWT_SECRET || "supersecretjwtkey1234567890!");
      const { payload } = await jwtVerify(token, secret);
      const user = {
        id: payload.id,
        email: payload.email,
        role: payload.role,
        name: payload.name
      };
      if (roles && roles.length > 0 && !roles.includes(user.role)) {
        return c.json({
          success: false,
          error: "Forbidden: Insufficient permissions"
        }, 403);
      }
      c.set("user", user);
      await next();
    } catch {
      return c.json({
        success: false,
        error: "Unauthorized: Invalid or expired token"
      }, 401);
    }
  };
}

