// src/catalog/core/Category.ts
class Category {
  id;
  name;
  slug;
  description;
  isActive;
  createdAt;
  updatedAt;
  constructor(id, name, slug, description, isActive, createdAt, updatedAt) {
    this.id = id;
    this.name = name;
    this.slug = slug;
    this.description = description;
    this.isActive = isActive;
    this.createdAt = createdAt;
    this.updatedAt = updatedAt;
  }
  static create(params) {
    const now = new Date().toISOString();
    return new Category(params.id, params.name, params.slug, params.description ?? null, params.isActive ?? true, params.createdAt ?? now, params.updatedAt ?? now);
  }
}

// src/shared/utils/slug.ts
function generateSlug(text2) {
  return text2.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9\s-]/g, "").trim().replace(/\s+/g, "-").replace(/-+/g, "-");
}

// src/catalog/core/CreateCategoryUseCase.ts
class CreateCategoryUseCase {
  categoryRepository;
  constructor(categoryRepository) {
    this.categoryRepository = categoryRepository;
  }
  async execute(dto) {
    const existingCategory = await this.categoryRepository.findByName(dto.name);
    if (existingCategory) {
      throw new Error("Category name already exists");
    }
    const slug = generateSlug(dto.name);
    const newCategory = Category.create({
      id: crypto.randomUUID(),
      name: dto.name,
      slug,
      description: dto.description,
      isActive: true
    });
    await this.categoryRepository.save(newCategory);
    return newCategory;
  }
}

