// src/catalog/core/CreateProductUseCase.ts
class CreateProductUseCase {
  productRepository;
  categoryRepository;
  constructor(productRepository, categoryRepository) {
    this.productRepository = productRepository;
    this.categoryRepository = categoryRepository;
  }
  async execute(dto) {
    if (dto.basePrice <= 0) {
      throw new Error("Base price must be greater than 0");
    }
    const category = await this.categoryRepository.findById(dto.categoryId);
    if (!category) {
      throw new Error("Category not found");
    }
    const seenCombos = new Set;
    for (const v of dto.variants) {
      const comboKey = `${v.size.toLowerCase()}_${v.color.toLowerCase()}`;
      if (seenCombos.has(comboKey)) {
        throw new Error(`Duplicate variant size and color combo found: Size: ${v.size}, Color: ${v.color}`);
      }
      seenCombos.add(comboKey);
    }
    const productId = crypto.randomUUID();
    const slug = generateSlug(dto.name);
    const existingProduct = await this.productRepository.findBySlug(slug);
    if (existingProduct) {
      throw new Error("Ya existe un producto con este nombre o un nombre similar");
    }
    const domainVariants = dto.variants.map((v) => ProductVariant.create({
      id: crypto.randomUUID(),
      productId,
      size: v.size,
      color: v.color,
      sku: v.sku,
      stock: v.stock ?? 0,
      additionalPrice: v.additionalPrice ?? 0
    }));
    const newProduct = Product.create({
      id: productId,
      name: dto.name,
      slug,
      description: dto.description,
      basePrice: dto.basePrice,
      categoryId: dto.categoryId,
      isActive: true,
      variants: domainVariants,
      images: []
    });
    await this.productRepository.save(newProduct);
    return newProduct;
  }
}

