// src/catalog/core/UploadProductImageUseCase.ts
class UploadProductImageUseCase {
  productRepository;
  storageService;
  constructor(productRepository, storageService) {
    this.productRepository = productRepository;
    this.storageService = storageService;
  }
  async execute(dto) {
    const product = await this.productRepository.findById(dto.productId);
    if (!product) {
      throw new Error("Product not found");
    }
    if (product.images.length >= 5) {
      throw new Error("Product has reached the limit of 5 images");
    }
    const position = product.images.length;
    const uniqueId = crypto.randomUUID();
    const extension = dto.fileName.split(".").pop() || "jpg";
    const bucketKey = `products/${product.id}/${uniqueId}.${extension}`;
    const fileUrl = await this.storageService.upload(dto.fileBuffer, bucketKey, dto.contentType, dto.origin);
    const newImage = ProductImage.create({
      id: uniqueId,
      productId: product.id,
      url: fileUrl,
      position
    });
    await this.productRepository.saveImage(newImage);
    return newImage;
  }
}

// src/catalog/adapters/SqliteCategoryRepo.ts
class SqliteCategoryRepo {
  toDomain(row) {
    return new Category(row.id, row.name, row.slug, row.description, row.isActive === 1, row.createdAt, row.updatedAt);
  }
  async findById(id) {
    const [row] = await db.select().from(categories).where(eq(categories.id, id)).limit(1);
    return row ? this.toDomain(row) : null;
  }
  async findByName(name) {
    const [row] = await db.select().from(categories).where(eq(categories.name, name)).limit(1);
    return row ? this.toDomain(row) : null;
  }
  async findBySlug(slug) {
    const [row] = await db.select().from(categories).where(eq(categories.slug, slug)).limit(1);
    return row ? this.toDomain(row) : null;
  }
  async save(category) {
    await db.insert(categories).values({
      id: category.id,
      name: category.name,
      slug: category.slug,
      description: category.description,
      isActive: category.isActive ? 1 : 0,
      createdAt: category.createdAt,
      updatedAt: category.updatedAt
    }).onConflictDoUpdate({
      target: categories.id,
      set: {
        name: category.name,
        slug: category.slug,
        description: category.description,
        isActive: category.isActive ? 1 : 0,
        updatedAt: new Date().toISOString()
      }
    });
  }
  async listAll() {
    const rows = await db.select().from(categories);
    return rows.map((r) => this.toDomain(r));
  }
  async hasAssociatedProducts(categoryId) {
    const [row] = await db.select({ count: sql`count(*)` }).from(products).where(eq(products.categoryId, categoryId)).limit(1);
    return Number(row?.count || 0) > 0;
  }
  async delete(id) {
    await db.delete(categories).where(eq(categories.id, id));
  }
}

// src/catalog/adapters/SqliteProductRepo.ts
class SqliteProductRepo {
  toDomain(row, variantRows, imageRows) {
    const variants = variantRows.map((v) => new ProductVariant(v.id, v.productId, v.size, v.color, v.sku, v.stock, v.additionalPrice, v.createdAt, v.updatedAt));
    const images = imageRows.map((img) => new ProductImage(img.id, img.productId, img.url, img.position, img.createdAt));
    return new Product(row.id, row.name, row.slug, row.description, row.basePrice, row.categoryId, row.isActive === 1, row.createdAt, row.updatedAt, variants, images);
  }
  async findById(id) {
    const [row] = await db.select().from(products).where(eq(products.id, id)).limit(1);
    if (!row)
      return null;
    const variantRows = await db.select().from(productVariants).where(eq(productVariants.productId, id));
    const imageRows = await db.select().from(productImages).where(eq(productImages.productId, id));
    return this.toDomain(row, variantRows, imageRows);
  }
  async findBySlug(slug) {
    const [row] = await db.select().from(products).where(eq(products.slug, slug)).limit(1);
    if (!row)
      return null;
    const variantRows = await db.select().from(productVariants).where(eq(productVariants.productId, row.id));
    const imageRows = await db.select().from(productImages).where(eq(productImages.productId, row.id));
    return this.toDomain(row, variantRows, imageRows);
  }
  async save(product) {
    await db.transaction(async (tx) => {
      await tx.insert(products).values({
        id: product.id,
        name: product.name,
        slug: product.slug,
        description: product.description,
        basePrice: product.basePrice,
        categoryId: product.categoryId,
        isActive: product.isActive ? 1 : 0,
        createdAt: product.createdAt,
        updatedAt: product.updatedAt
      }).onConflictDoUpdate({
        target: products.id,
        set: {
          name: product.name,
          slug: product.slug,
          description: product.description,
          basePrice: product.basePrice,
          categoryId: product.categoryId,
          isActive: product.isActive ? 1 : 0,
          updatedAt: new Date().toISOString()
        }
      });
      for (const v of product.variants) {
        await tx.insert(productVariants).values({
          id: v.id,
          productId: v.productId,
          size: v.size,
          color: v.color,
          sku: v.sku,
          stock: v.stock,
          additionalPrice: v.additionalPrice,
          createdAt: v.createdAt,
          updatedAt: v.updatedAt
        }).onConflictDoUpdate({
          target: productVariants.id,
          set: {
            size: v.size,
            color: v.color,
            sku: v.sku,
            stock: v.stock,
            additionalPrice: v.additionalPrice,
            updatedAt: new Date().toISOString()
          }
        });
      }
    });
  }
  async list(params) {
    const limit = params.limit ?? 10;
    const offset = params.offset ?? 0;
    const conditions = [];
    if (params.categorySlug) {
      const [category] = await db.select().from(categories).where(eq(categories.slug, params.categorySlug)).limit(1);
      if (category) {
        conditions.push(eq(products.categoryId, category.id));
      } else {
        return { products: [], total: 0 };
      }
    }
    if (params.search) {
      conditions.push(like(products.name, `%${params.search}%`));
    }
    if (!params.includeInactive) {
      conditions.push(eq(products.isActive, 1));
    }
    const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
    const [countRow] = await db.select({ count: sql`count(*)` }).from(products).where(whereClause);
    const total = Number(countRow?.count || 0);
    if (total === 0) {
      return { products: [], total: 0 };
    }
    const productRows = await db.select().from(products).where(whereClause).limit(limit).offset(offset);
    const productIds = productRows.map((p) => p.id);
    const variantRows = await db.select().from(productVariants).where(inArray(productVariants.productId, productIds));
    const imageRows = await db.select().from(productImages).where(inArray(productImages.productId, productIds));
    const mappedProducts = productRows.map((row) => {
      const pVariants = variantRows.filter((v) => v.productId === row.id);
      const pImages = imageRows.filter((img) => img.productId === row.id);
      return this.toDomain(row, pVariants, pImages);
    });
    return {
      products: mappedProducts,
      total
    };
  }
  async saveImage(image) {
    await db.insert(productImages).values({
      id: image.id,
      productId: image.productId,
      url: image.url,
      position: image.position,
      createdAt: image.createdAt
    }).onConflictDoUpdate({
      target: productImages.id,
      set: {
        url: image.url,
        position: image.position
      }
    });
  }
  async deleteImage(id) {
    await db.delete(productImages).where(eq(productImages.id, id));
  }
  async findVariantById(id) {
    const [row] = await db.select().from(productVariants).where(eq(productVariants.id, id)).limit(1);
    if (!row)
      return null;
    return new ProductVariant(row.id, row.productId, row.size, row.color, row.sku, row.stock, row.additionalPrice, row.createdAt, row.updatedAt);
  }
  async updateVariantStock(variantId, newStock) {
    await db.update(productVariants).set({
      stock: newStock,
      updatedAt: new Date().toISOString()
    }).where(eq(productVariants.id, variantId));
  }
  async delete(id) {
    await db.transaction(async (tx) => {
      await tx.delete(productImages).where(eq(productImages.productId, id));
      await tx.delete(productVariants).where(eq(productVariants.productId, id));
      await tx.delete(products).where(eq(products.id, id));
    });
  }
}

// src/catalog/adapters/StorageService.ts
import { S3Client, PutObjectCommand, DeleteObjectCommand } from "@aws-sdk/client-s3";
import * as fs from "fs";
import * as path from "path";

class StorageService {
  s3Client = null;
  bucketName;
  isMock = true;
  constructor() {
    this.bucketName = process.env.R2_BUCKET_NAME || "smartpyme-images";
    const accessKeyId = process.env.R2_ACCESS_KEY_ID;
    const secretAccessKey = process.env.R2_SECRET_ACCESS_KEY;
    const endpoint = process.env.R2_ENDPOINT;
    if (accessKeyId && accessKeyId !== "mock_r2_access_key" && secretAccessKey && secretAccessKey !== "mock_r2_secret_key" && endpoint) {
      this.isMock = false;
      this.s3Client = new S3Client({
        region: "auto",
        endpoint,
        credentials: {
          accessKeyId,
          secretAccessKey
        }
      });
    }
  }
  async upload(fileBuffer, fileName, contentType, origin) {
    if (this.isMock) {
      const relativePath = path.join("public", "uploads", fileName);
      const fullPath = path.join(process.cwd(), relativePath);
      fs.mkdirSync(path.dirname(fullPath), { recursive: true });
      fs.writeFileSync(fullPath, fileBuffer);
      const baseOrigin = origin || `http://localhost:${process.env.PORT || 3000}`;
      return `${baseOrigin}/uploads/${fileName}`;
    }
    const command = new PutObjectCommand({
      Bucket: this.bucketName,
      Key: fileName,
      Body: fileBuffer,
      ContentType: contentType
    });
    await this.s3Client.send(command);
    const customDomain = process.env.R2_CUSTOM_DOMAIN;
    if (customDomain) {
      return `${customDomain}/${fileName}`;
    }
    return `${process.env.R2_ENDPOINT}/${this.bucketName}/${fileName}`;
  }
  async delete(fileUrl) {
    if (this.isMock) {
      const parts = fileUrl.split("/uploads/");
      const fileName = parts[1];
      if (fileName) {
        const fullPath = path.join(process.cwd(), "public", "uploads", fileName);
        if (fs.existsSync(fullPath)) {
          fs.unlinkSync(fullPath);
        }
      }
      return;
    }
    const key = fileUrl.split("/").slice(4).join("/");
    const command = new DeleteObjectCommand({
      Bucket: this.bucketName,
      Key: key
    });
    await this.s3Client.send(command);
  }
}

// src/catalog/adapters/CatalogController.ts
var catalogRouter = new Hono2;
var categoryRepo = new SqliteCategoryRepo;
var productRepo = new SqliteProductRepo;
var storageService = new StorageService;
var createCategoryUseCase = new CreateCategoryUseCase(categoryRepo);
var createProductUseCase = new CreateProductUseCase(productRepo, categoryRepo);
var uploadProductImageUseCase = new UploadProductImageUseCase(productRepo, storageService);
var createCategorySchema = exports_external.object({
  name: exports_external.string().min(2, "El nombre debe tener al menos 2 caracteres"),
  description: exports_external.string().optional()
});
var createProductSchema = exports_external.object({
  name: exports_external.string().min(2, "El nombre del producto debe tener al menos 2 caracteres"),
  description: exports_external.string().optional(),
  basePrice: exports_external.number().int().positive("El precio base debe ser mayor a 0"),
  categoryId: exports_external.string().uuid("El id de la categoría debe ser un UUID válido"),
  variants: exports_external.array(exports_external.object({
    size: exports_external.string().min(1, "La talla es obligatoria"),
    color: exports_external.string().min(1, "El color es obligatorio"),
    sku: exports_external.string().min(3, "El SKU debe tener al menos 3 caracteres"),
    stock: exports_external.number().int().nonnegative("El stock no puede ser negativo").optional(),
    additionalPrice: exports_external.number().int().nonnegative("El precio adicional no puede ser negativo").optional()
  })).min(1, "Debe tener al menos una variante")
});
catalogRouter.post("/categories", authMiddleware(["admin"]), async (c) => {
  try {
    const body = await c.req.json().catch(() => ({}));
    const validation = createCategorySchema.safeParse(body);
    if (!validation.success) {
      return c.json({ success: false, errors: validation.error.flatten().fieldErrors }, 400);
    }
    const category = await createCategoryUseCase.execute(validation.data);
    return c.json({ success: true, category }, 201);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 400);
  }
});
catalogRouter.get("/categories", async (c) => {
  try {
    const list = await categoryRepo.listAll();
    return c.json({ success: true, categories: list }, 200);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
catalogRouter.post("/products", authMiddleware(["admin"]), async (c) => {
  try {
    const body = await c.req.json().catch(() => ({}));
    const validation = createProductSchema.safeParse(body);
    if (!validation.success) {
      return c.json({ success: false, errors: validation.error.flatten().fieldErrors }, 400);
    }
    const product = await createProductUseCase.execute(validation.data);
    return c.json({ success: true, product }, 201);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 400);
  }
});
catalogRouter.get("/products", async (c) => {
  try {
    const categorySlug = c.req.query("category");
    const search = c.req.query("q");
    const limit = c.req.query("limit") ? parseInt(c.req.query("limit")) : 10;
    const offset = c.req.query("offset") ? parseInt(c.req.query("offset")) : 0;
    const includeInactive = c.req.query("includeInactive") === "true";
    const result = await productRepo.list({
      categorySlug,
      search,
      limit,
      offset,
      includeInactive
    });
    return c.json({ success: true, ...result }, 200);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
catalogRouter.get("/products/:slug", async (c) => {
  try {
    const slug = c.req.param("slug");
    const product = await productRepo.findBySlug(slug);
    if (!product) {
      return c.json({ success: false, error: "Product not found" }, 404);
    }
    return c.json({ success: true, product }, 200);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
catalogRouter.post("/products/:id/images", authMiddleware(["admin"]), async (c) => {
  try {
    const productId = c.req.param("id");
    const body = await c.req.parseBody();
    const file2 = body["file"];
    if (!file2 || !(file2 instanceof File)) {
      return c.json({ success: false, error: "No image file provided in field 'file'" }, 400);
    }
    if (file2.size > 5 * 1024 * 1024) {
      return c.json({ success: false, error: "El tamaño del archivo no debe exceder 5 MB" }, 400);
    }
    const allowedTypes = ["image/jpeg", "image/png", "image/webp"];
    if (!allowedTypes.includes(file2.type)) {
      return c.json({ success: false, error: "Formato inválido. Solo se admiten JPG, PNG y WebP" }, 400);
    }
    const arrayBuffer = await file2.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);
    const origin = new URL(c.req.url).origin;
    const image = await uploadProductImageUseCase.execute({
      productId,
      fileBuffer: buffer,
      fileName: file2.name,
      contentType: file2.type,
      origin
    });
    return c.json({ success: true, image }, 201);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 400);
  }
});
catalogRouter.delete("/products/:id", authMiddleware(["admin"]), async (c) => {
  try {
    const id = c.req.param("id");
    const product = await productRepo.findById(id);
    if (!product) {
      return c.json({ success: true, message: "Product deleted successfully (already gone)" }, 200);
    }
    await productRepo.delete(id);
    return c.json({ success: true, message: "Product deleted successfully" }, 200);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});

// src/cart/core/Cart.ts
class Cart {
  id;
  customerId;
  sessionId;
  status;
  createdAt;
  updatedAt;
  items;
  constructor(id, customerId, sessionId, status, createdAt, updatedAt, items = []) {
    this.id = id;
    this.customerId = customerId;
    this.sessionId = sessionId;
    this.status = status;
    this.createdAt = createdAt;
    this.updatedAt = updatedAt;
    this.items = items;
  }
  static create(params) {
    const now = new Date().toISOString();
    return new Cart(params.id, params.customerId ?? null, params.sessionId ?? null, params.status ?? "active", params.createdAt ?? now, params.updatedAt ?? now, params.items ?? []);
  }
  getSubtotal() {
    return this.items.reduce((sum, item) => sum + item.quantity * item.unitPriceSnapshot, 0);
  }
}

