ordersRouter.get("/orders/:id", async (c) => {
  try {
    const id = c.req.param("id");
    const order = await orderRepo.findById(id);
    if (!order) {
      return c.json({ success: false, error: "Order not found" }, 404);
    }
    const authHeader = c.req.header("Authorization");
    const customerId = await getCustomerId2(authHeader);
    let isAdmin = false;
    if (authHeader && authHeader.startsWith("Bearer ")) {
      try {
        const token = authHeader.substring(7);
        const secret = new TextEncoder().encode(process.env.JWT_SECRET || "supersecretjwtkey1234567890!");
        const { payload } = await jwtVerify(token, secret);
        isAdmin = payload.role === "admin";
      } catch {}
    }
    if (!isAdmin && order.customerId && order.customerId !== customerId) {
      return c.json({ success: false, error: "Forbidden: You do not own this order" }, 403);
    }
    return c.json({ success: true, order }, 200);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
ordersRouter.patch("/orders/:id/status", authMiddleware(["admin"]), async (c) => {
  try {
    const id = c.req.param("id");
    const body = await c.req.json().catch(() => ({}));
    const validation = updateStatusSchema.safeParse(body);
    if (!validation.success) {
      return c.json({ success: false, errors: validation.error.flatten().fieldErrors }, 400);
    }
    const order = await orderRepo.findById(id);
    if (!order) {
      return c.json({ success: false, error: "Order not found" }, 404);
    }
    const currentStatus = order.status;
    const newStatus = validation.data.status;
    const allowedTransitions = {
      pendiente: ["pagado", "cancelado", "fallido"],
      pagado: ["enviado", "cancelado"],
      enviado: ["entregado"],
      entregado: [],
      cancelado: [],
      fallido: []
    };
    if (!allowedTransitions[currentStatus]?.includes(newStatus)) {
      return c.json({
        success: false,
        error: `Transición de estado inválida: de '${currentStatus}' a '${newStatus}'`
      }, 400);
    }
    const updatedOrder = Order.create({
      ...order,
      status: newStatus,
      updatedAt: new Date().toISOString()
    });
    await orderRepo.save(updatedOrder);
    if (newStatus === "pagado" && currentStatus === "pendiente") {
      for (const item of order.items) {
        await decrementStockUseCase.execute({
          productVariantId: item.productVariantId,
          quantity: item.quantity,
          referenceType: "order",
          referenceId: order.id
        });
      }
      const payment = Payment.create({
        id: crypto.randomUUID(),
        orderId: order.id,
        amount: order.total,
        currency: order.currency,
        status: "succeeded",
        method: "manual"
      });
      await orderRepo.savePayment(payment);
      let cart = null;
      if (order.customerId) {
        cart = await cartRepo2.findActiveByCustomerId(order.customerId);
      } else if (order.items.length > 0 && order.items[0]) {
        cart = await cartRepo2.findActiveCartByVariantId(order.items[0].productVariantId);
      }
      if (cart) {
        const convertedCart = Cart.create({
          ...cart,
          status: "converted",
          updatedAt: new Date().toISOString()
        });
        await cartRepo2.save(convertedCart);
        await cartRepo2.deleteItemsByCartId(cart.id);
      }
    }
    if (newStatus === "cancelado" && currentStatus === "pagado") {
      for (const item of order.items) {
        const variant = await productRepo3.findVariantById(item.productVariantId);
        if (variant) {
          const restoredStock = variant.stock + item.quantity;
          await productRepo3.updateVariantStock(item.productVariantId, restoredStock);
          const restoreMovement = {
            id: crypto.randomUUID(),
            productVariantId: item.productVariantId,
            type: "cancellation",
            quantity: item.quantity,
            previousStock: variant.stock,
            newStock: restoredStock,
            referenceType: "order",
            referenceId: order.id,
            notes: "Restocked due to order cancellation",
            createdAt: new Date().toISOString(),
            createdBy: c.get("user")?.id || null
          };
          await inventoryRepo.saveMovement(restoreMovement);
        }
      }
    }
    return c.json({ success: true, order: updatedOrder }, 200);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 400);
  }
});
ordersRouter.post("/payments/webhook", async (c) => {
  const stripeSecret = process.env.STRIPE_SECRET_KEY;
  const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;
  const signature = c.req.header("stripe-signature");
  if (!stripeSecret || stripeSecret === "sk_test_mock_key" || !webhookSecret || !signature) {
    try {
      const body = await c.req.json().catch(() => ({}));
      if (body.type === "payment_intent.succeeded") {
        const paymentIntentId = body.data?.object?.id;
        if (paymentIntentId) {
          await confirmPaymentUseCase.execute({ stripePaymentIntentId: paymentIntentId });
          return c.json({ received: true, mocked: true });
        }
      }
      return c.json({ received: true, message: "Mock webhook ignored or processed" });
    } catch (error51) {
      return c.json({ error: error51.message }, 400);
    }
  }
  try {
    const rawBody = await c.req.text();
    const stripe = new stripe_esm_node_default(stripeSecret, { apiVersion: "2023-10-16" });
    const event = stripe.webhooks.constructEvent(rawBody, signature, webhookSecret);
    if (event.type === "payment_intent.succeeded") {
      const paymentIntent = event.data.object;
      await confirmPaymentUseCase.execute({ stripePaymentIntentId: paymentIntent.id });
    } else if (event.type === "payment_intent.payment_failed") {
      const paymentIntent = event.data.object;
      try {
        await confirmPaymentUseCase.execute({ stripePaymentIntentId: paymentIntent.id });
      } catch {}
    }
    return c.json({ received: true });
  } catch (error51) {
    return c.json({ error: `Webhook Error: ${error51.message}` }, 400);
  }
});

