// src/inventory/adapters/InventoryController.ts
var inventoryRouter = new Hono2;
var inventoryRepo2 = new SqliteInventoryRepo;
var productRepo4 = new SqliteProductRepo;
inventoryRouter.use("*", authMiddleware(["admin"]));
var restockSchema = exports_external.object({
  productVariantId: exports_external.string().uuid("El id de la variante debe ser un UUID válido"),
  quantity: exports_external.number().int().positive("La cantidad a reabastecer debe ser mayor a 0"),
  notes: exports_external.string().optional()
});
inventoryRouter.get("/alerts", async (c) => {
  try {
    const alerts = await inventoryRepo2.listAlerts("active");
    return c.json({ success: true, alerts });
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
inventoryRouter.post("/restock", async (c) => {
  try {
    const body = await c.req.json().catch(() => ({}));
    const validation = restockSchema.safeParse(body);
    if (!validation.success) {
      return c.json({ success: false, errors: validation.error.flatten().fieldErrors }, 400);
    }
    const { productVariantId, quantity, notes } = validation.data;
    const variant = await productRepo4.findVariantById(productVariantId);
    if (!variant) {
      return c.json({ success: false, error: "Product variant not found" }, 404);
    }
    const previousStock = variant.stock;
    const newStock = previousStock + quantity;
    await productRepo4.updateVariantStock(productVariantId, newStock);
    const movement = StockMovement.create({
      id: crypto.randomUUID(),
      productVariantId,
      type: "restock",
      quantity,
      previousStock,
      newStock,
      referenceType: "restock",
      notes: notes || "Manual restock",
      createdBy: c.get("user")?.id || null
    });
    await inventoryRepo2.saveMovement(movement);
    if (newStock >= 5) {
      const activeAlert = await inventoryRepo2.findActiveAlertByVariantId(productVariantId);
      if (activeAlert) {
        const resolvedAlert = StockAlert.create({
          ...activeAlert,
          status: "resolved",
          resolvedAt: new Date().toISOString()
        });
        await inventoryRepo2.saveAlert(resolvedAlert);
      }
    }
    return c.json({
      success: true,
      message: `Restocked ${quantity} units successfully. New stock: ${newStock}`
    });
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 400);
  }
});

